export type Customer = {
  yearsWithMHPCO: number;
};

export type Item = {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
};

export type QuoteOptions = {
  isFirstInsurance: boolean;
};

const BASE_PREMIUMS: Record<string, number> = { sword: 100, amulet: 60, rune: 25 };
const BUNDLE_BASE_PREMIUM = 60; // 3 alike components at special rate
const PROCESSING_FEE = 5;

export const quote = (
  customer: Customer,
  items: Item[],
  options: QuoteOptions
): number => {
  const isBundle = items.length === 3 &&
    items.every(item => item.type === items[0].type) &&
    BASE_PREMIUMS[items[0].type] === 25;
  const totalBase = isBundle ? 60 : items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const multipliers = [
    options.isFirstInsurance ? 110 : 85,
    items.some(item => item.cursed) ? 150 : 100,
    items.some(item => item.enchantment >= 5) ? 130 : 100,
    customer.yearsWithMHPCO >= 2 ? 80 : 100,
  ];
  const rawPremium = multipliers.reduce((p, m) => p * m, totalBase);
  return Math.ceil(rawPremium / 100 ** multipliers.length) + PROCESSING_FEE;
};

export type Policy = {
  insuranceSum: number;
  remainingCap: number;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type Incident = {
  cause: string;
  damages: Damage[];
};

export const claim = (
  policy: Policy,
  incident: Incident
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote", () => {
    it("should quote a single sword for a first-time customer with processing fee", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 3, cursed: false }];
      expect(quote(customer, items, { isFirstInsurance: true })).toBe(115);
    });
    it("should quote a single amulet for a first-time customer", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }];
      expect(quote(customer, items, { isFirstInsurance: true })).toBe(71);
    });
    it("should quote multiple items together", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [
        { type: "sword", material: "steel", enchantment: 3, cursed: false },
        { type: "amulet", material: "silver", enchantment: 2, cursed: false },
      ];
      expect(quote(customer, items, { isFirstInsurance: true })).toBe(181);
    });
    it("should apply cursed item surcharge of 50%", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 3, cursed: true }];
      expect(quote(customer, items, { isFirstInsurance: true })).toBe(170);
    });
    it("should apply high enchantment surcharge of 30% for enchantment >= 5", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 5, cursed: false }];
      expect(quote(customer, items, { isFirstInsurance: true })).toBe(148);
    });
    it("should apply loyalty discount of 20% for customers with >= 2 years", () => {
      const customer = { yearsWithMHPCO: 3 };
      const items = [{ type: "sword", material: "steel", enchantment: 3, cursed: false }];
      expect(quote(customer, items, { isFirstInsurance: true })).toBe(93);
    });
    it("should apply subsequent contract discount of 15%", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [{ type: "sword", material: "steel", enchantment: 3, cursed: false }];
      expect(quote(customer, items, { isFirstInsurance: false })).toBe(90);
    });
    it("should apply bundle pricing for 3 alike components", () => {
      const customer = { yearsWithMHPCO: 0 };
      const items = [
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
        { type: "rune", material: "stone", enchantment: 0, cursed: false },
      ];
      expect(quote(customer, items, { isFirstInsurance: true })).toBe(71);
    });
  });

  describe("Claim", () => {
    it.todo("should process a basic claim subtracting the 100G deductible");
    it.todo("should track remaining cap after a claim");
    it.todo("should reimburse high enchantment damage (>= 8) at 50%");
    it.todo("should reimburse dragon material damage at 100%");
  });
});

